import{_ as a}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as t,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Étiquetage automatique","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Other/auto-tagging.md","filePath":"fr-FR/Other/auto-tagging.md","lastUpdated":1781962217000}'),o={name:"fr-FR/Other/auto-tagging.md"};function r(n,e,d,u,p,c){return i(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="etiquetage-automatique" tabindex="-1">Étiquetage automatique <a class="header-anchor" href="#etiquetage-automatique" aria-label="Permalink to &quot;Étiquetage automatique&quot;">​</a></h1><p>L’étiquetage automatique se configure ici :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Paramètres système -&gt; Autres paramètres -&gt; Étiquetage automatique</span></span></code></pre></div><p>Il génère des tags pour les images afin de faciliter la recherche, les filtres de l’API aléatoire, la galerie publique et le contrôle d’accès par classification d’âge.</p><h2 id="ce-que-cela-fait" tabindex="-1">Ce que cela fait <a class="header-anchor" href="#ce-que-cela-fait" aria-label="Permalink to &quot;Ce que cela fait&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fonction</th><th>Description</th></tr></thead><tbody><tr><td>Tags de contenu</td><td>Ajoute des tags de personnes, scènes, objets, style visuel, etc.</td></tr><tr><td>Tags de personnage</td><td>Utile pour les images d’anime et les illustrations</td></tr><tr><td>Tags d’orientation</td><td>Ajoute <code>landscape</code>, <code>portrait</code> ou <code>square</code></td></tr><tr><td>Classification d’image</td><td>Enregistre les résultats <code>G/S/Q/E</code></td></tr><tr><td>Étiquetage à l’upload</td><td>Traite automatiquement les nouvelles images</td></tr><tr><td>Étiquetage par lot</td><td>Ajoute des tags à d’anciennes images dans un ou plusieurs dossiers</td></tr></tbody></table><h2 id="a-preparer" tabindex="-1">À préparer <a class="header-anchor" href="#a-preparer" aria-label="Permalink to &quot;À préparer&quot;">​</a></h2><p>Vous avez besoin d’au moins une URL accessible de Hugging Face Space.</p><p>La méthode recommandée consiste à dupliquer le Space <code>wd-tagger</code> de SmilingWolf dans votre propre compte Hugging Face :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Vous pouvez utiliser le Space public pour tester, mais il est partagé par de nombreux utilisateurs et peut être lent, en file d’attente ou indisponible. Pour un usage régulier, une copie personnelle est plus stable.</p><h2 id="dupliquer-le-space" tabindex="-1">Dupliquer le Space <a class="header-anchor" href="#dupliquer-le-space" aria-label="Permalink to &quot;Dupliquer le Space&quot;">​</a></h2><ol><li>Connectez-vous à Hugging Face.</li><li>Ouvrez <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+a+`" alt="Space public de SmilingWolf" loading="lazy"></p><ol start="3"><li>Ouvrez le menu en haut à droite.</li><li>Choisissez <code>Duplicate this Space</code>.</li><li>Gardez le nom ou utilisez un nom clair, par exemple <code>wd-tagger</code>.</li><li>Laissez-le en <code>Public</code> pour faciliter les appels depuis ImgBed.</li><li>Commencez avec le matériel gratuit.</li><li>Créez le Space et attendez la fin du build.</li></ol><p>Copiez ensuite l’URL du navigateur et collez-la dans <code>Space URLs</code> dans ImgBed.</p><h2 id="reglages-conseilles" tabindex="-1">Réglages conseillés <a class="header-anchor" href="#reglages-conseilles" aria-label="Permalink to &quot;Réglages conseillés&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommandation</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Une URL par ligne</td></tr><tr><td>Dossier cible</td><td>Vide pour tout traiter ; choisissez un dossier pour limiter</td></tr><tr><td>Modèle</td><td>Commencez avec <code>wd-swinv2-tagger-v3</code></td></tr><tr><td>Seuil des tags généraux</td><td>Commencez autour de <code>0.35</code></td></tr><tr><td>Seuil des personnages</td><td>Autour de <code>0.85</code> pour réduire les faux positifs</td></tr><tr><td><code>MCut</code></td><td>Laissez désactivé au début</td></tr><tr><td>Étiquetage à l’upload</td><td>Activez si les nouvelles images doivent être traitées automatiquement</td></tr></tbody></table><p>Si trop de tags sont générés, augmentez légèrement le seuil général. S’il y en a trop peu, baissez-le un peu.</p><h2 id="etiquetage-par-lot" tabindex="-1">Étiquetage par lot <a class="header-anchor" href="#etiquetage-par-lot" aria-label="Permalink to &quot;Étiquetage par lot&quot;">​</a></h2><ol><li>Renseignez <code>Space URLs</code>.</li><li>Sélectionnez un dossier cible.</li><li>Lancez l’étiquetage.</li><li>Attendez la fin de la progression.</li></ol><p>Si le dossier cible est vide, ImgBed traite tous les dossiers.</p><h2 id="etiquetage-a-l-upload" tabindex="-1">Étiquetage à l’upload <a class="header-anchor" href="#etiquetage-a-l-upload" aria-label="Permalink to &quot;Étiquetage à l’upload&quot;">​</a></h2><p>Avec cette option active, les nouvelles images appellent automatiquement les <code>Space URLs</code> configurés.</p><p>Si le Space est en file d’attente, l’upload peut se terminer avant l’étiquetage, qui continue ensuite en arrière-plan.</p><h2 id="questions-frequentes" tabindex="-1">Questions fréquentes <a class="header-anchor" href="#questions-frequentes" aria-label="Permalink to &quot;Questions fréquentes&quot;">​</a></h2><h3 id="pourquoi-dupliquer-mon-propre-space" tabindex="-1">Pourquoi dupliquer mon propre Space ? <a class="header-anchor" href="#pourquoi-dupliquer-mon-propre-space" aria-label="Permalink to &quot;Pourquoi dupliquer mon propre Space ?&quot;">​</a></h3><p>Les Spaces publics sont partagés par beaucoup d’utilisateurs. Une copie personnelle est généralement plus rapide et plus stable pour votre site.</p><h3 id="pourquoi-les-tags-sont-ils-en-anglais" tabindex="-1">Pourquoi les tags sont-ils en anglais ? <a class="header-anchor" href="#pourquoi-les-tags-sont-ils-en-anglais" aria-label="Permalink to &quot;Pourquoi les tags sont-ils en anglais ?&quot;">​</a></h3><p>C’est normal. Les modèles SmilingWolf renvoient des tags en anglais. ImgBed les utilise pour la recherche, les filtres, l’API aléatoire et la galerie publique.</p><h3 id="a-quoi-sert-la-classification" tabindex="-1">À quoi sert la classification ? <a class="header-anchor" href="#a-quoi-sert-la-classification" aria-label="Permalink to &quot;À quoi sert la classification ?&quot;">​</a></h3><p>La classification fonctionne avec le mode d’accès de sécurité. Par exemple, si vous limitez les visiteurs selon l’âge, la galerie et l’API aléatoire suivent ces règles.</p><h2 id="flux-rapide" tabindex="-1">Flux rapide <a class="header-anchor" href="#flux-rapide" aria-label="Permalink to &quot;Flux rapide&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Se connecter à Hugging Face</span></span>
<span class="line"><span>-&gt; Ouvrir SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Dupliquer le Space</span></span>
<span class="line"><span>-&gt; Attendre le build</span></span>
<span class="line"><span>-&gt; Copier l’URL du Space</span></span>
<span class="line"><span>-&gt; La coller dans Space URLs</span></span>
<span class="line"><span>-&gt; Régler modèle et seuils</span></span>
<span class="line"><span>-&gt; Lancer l’étiquetage ou activer l’étiquetage à l’upload</span></span></code></pre></div>`,34)])])}const q=t(o,[["render",r]]);export{m as __pageData,q as default};
